// migration.test.ts — the CI migration test. Seed an in-memory DB in the LEGACY
// shape (composite (user_id,id) PKs, prefixed ids, an archived row, a subtask, a
// multi-label task), run the migration, and assert: every row survives (incl.
// archived); every remapped parent/project/task_label ref resolves to a real new
// UUID; owner_id = creator_id; prefs carried; no grants.

import assert from 'node:assert';
import { test } from 'node:test';
import Database from 'better-sqlite3';
import { migrateFromLegacy } from '../scripts/migrate-from-legacy.js';
import { openDatabase } from '../src/db.js';

function seedLegacy(): Database.Database {
  const db = new Database(':memory:');
  db.pragma('foreign_keys = ON');
  db.exec(`
    CREATE TABLE users (
      id TEXT PRIMARY KEY, username TEXT, email TEXT, password_hash TEXT,
      state_version INTEGER DEFAULT 0, created_at TEXT, updated_at TEXT,
      theme TEXT, week_start INTEGER DEFAULT 1, sort_prefs TEXT,
      is_admin INTEGER DEFAULT 0, fib_sizing INTEGER DEFAULT 0
    );
    CREATE TABLE projects (
      user_id TEXT, id TEXT, parent_id TEXT, name TEXT, color TEXT, glyph TEXT,
      collapsed INTEGER DEFAULT 0, position INTEGER DEFAULT 0, archived INTEGER DEFAULT 0,
      health TEXT DEFAULT '[]', PRIMARY KEY (user_id, id)
    );
    CREATE TABLE tasks (
      user_id TEXT, id TEXT, project_id TEXT, parent_id TEXT, title TEXT,
      done INTEGER DEFAULT 0, due TEXT, reminder TEXT, recurrence TEXT, notes TEXT DEFAULT '',
      priority INTEGER DEFAULT 0, size INTEGER DEFAULT 0, created_at TEXT, completed_at TEXT,
      position INTEGER DEFAULT 0, archived INTEGER DEFAULT 0, PRIMARY KEY (user_id, id)
    );
    CREATE TABLE labels (
      user_id TEXT, id TEXT, name TEXT, pinned INTEGER DEFAULT 0, PRIMARY KEY (user_id, id)
    );
    CREATE TABLE task_labels (
      user_id TEXT, task_id TEXT, label_id TEXT, PRIMARY KEY (user_id, task_id, label_id)
    );
    CREATE TABLE saved_queries (
      user_id TEXT, id TEXT, name TEXT, glyph TEXT, query TEXT, system INTEGER DEFAULT 0,
      color TEXT, position INTEGER DEFAULT 0, pinned INTEGER DEFAULT 0, PRIMARY KEY (user_id, id)
    );
  `);

  db.prepare(
    `INSERT INTO users (id, username, email, password_hash, theme, week_start, sort_prefs, is_admin, fib_sizing, created_at, updated_at)
     VALUES ('u1', 'alice', 'alice@example.com', 'hash', 'matrix', 0, '{"order":["due"]}', 1, 1, '2025-01-01T00:00:00Z', '2025-02-01T00:00:00Z')`,
  ).run();

  const proj = db.prepare(
    'INSERT INTO projects (user_id, id, parent_id, name, color, glyph, archived) VALUES (?, ?, ?, ?, ?, ?, ?)',
  );
  proj.run('u1', 'p_inbox', null, 'inbox', '#ffb000', '⌂', 0);
  proj.run('u1', 'p_dev', null, 'dev', '#46d369', 'λ', 0);
  proj.run('u1', 'p_sub', 'p_dev', 'sub', '#3fd7d7', '◈', 0); // nested
  proj.run('u1', 'p_arch', null, 'archived-proj', '#ff5c5c', '✗', 1); // archived

  const label = db.prepare('INSERT INTO labels (user_id, id, name, pinned) VALUES (?, ?, ?, ?)');
  label.run('u1', 'l_a', 'urgent', 1);
  label.run('u1', 'l_b', 'bug', 0);

  const task = db.prepare(
    'INSERT INTO tasks (user_id, id, project_id, parent_id, title, done, due, created_at, archived) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)',
  );
  task.run('u1', 't1', 'p_dev', null, 'root task', 0, '2026-06-18', '2026-06-01', 0);
  task.run('u1', 't2', 'p_dev', 't1', 'subtask', 0, null, '2026-06-02', 0); // subtask of t1
  task.run('u1', 't3', 'p_inbox', null, 'archived task', 1, null, '2026-05-01', 1); // archived
  task.run('u1', 't4', 'p_sub', null, 'multi-label task', 0, null, '2026-06-03', 0);

  const tl = db.prepare('INSERT INTO task_labels (user_id, task_id, label_id) VALUES (?, ?, ?)');
  tl.run('u1', 't1', 'l_a');
  tl.run('u1', 't4', 'l_a');
  tl.run('u1', 't4', 'l_b');

  db.prepare(
    "INSERT INTO saved_queries (user_id, id, name, glyph, query, system, position, pinned) VALUES ('u1', 'sv_today', 'Today', '☉', 'status:open due:today', 1, 0, 0)",
  ).run();

  return db;
}

const rows = (db: Database.Database, sql: string): any[] => db.prepare(sql).all() as any[];
const count = (db: Database.Database, table: string): number =>
  (db.prepare(`SELECT COUNT(*) AS c FROM ${table}`).get() as { c: number }).c;
const isUuid = (s: string): boolean =>
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/.test(s);

test('migration: legacy prefixed ids -> UUIDs, survival + ref integrity', () => {
  const legacy = seedLegacy();
  const { sqlite: target } = openDatabase(':memory:');
  const stats = migrateFromLegacy(legacy, target);

  // ---- counts survive (incl. archived) ----
  assert.deepEqual(stats, {
    users: 1,
    projects: 4,
    tasks: 4,
    labels: 2,
    taskLabels: 3,
    savedQueries: 1,
  });
  assert.equal(count(target, 'projects'), 4); // p_arch archived row preserved
  assert.equal(count(target, 'tasks'), 4); // t3 archived row preserved
  assert.equal(count(target, 'task_labels'), 3);
  assert.equal(count(target, 'grants'), 0); // default private

  // ---- archived flags preserved ----
  const projByName = new Map(rows(target, 'SELECT * FROM projects').map((p) => [p.name, p]));
  assert.equal(projByName.get('archived-proj').archived, 1);
  const archTask = rows(target, 'SELECT * FROM tasks').find((t) => t.title === 'archived task');
  assert.equal(archTask.archived, 1);

  // ---- ids are UUIDs, not the legacy prefixed form ----
  const allIds = [
    ...rows(target, 'SELECT id FROM projects'),
    ...rows(target, 'SELECT id FROM tasks'),
    ...rows(target, 'SELECT id FROM labels'),
    ...rows(target, 'SELECT id FROM saved_queries'),
    ...rows(target, 'SELECT id FROM users'),
  ].map((r) => r.id);
  for (const id of allIds) assert.ok(isUuid(id), `expected UUID, got "${id}"`);

  // ---- ref integrity: every parent/project/task_label points at a real new id ----
  const userIds = new Set(rows(target, 'SELECT id FROM users').map((r) => r.id));
  const projIds = new Set(rows(target, 'SELECT id FROM projects').map((r) => r.id));
  const taskIds = new Set(rows(target, 'SELECT id FROM tasks').map((r) => r.id));
  const labelIds = new Set(rows(target, 'SELECT id FROM labels').map((r) => r.id));

  for (const p of rows(target, 'SELECT * FROM projects')) {
    assert.ok(userIds.has(p.owner_id));
    if (p.parent_id) assert.ok(projIds.has(p.parent_id), 'project parent_id resolves');
  }
  for (const t of rows(target, 'SELECT * FROM tasks')) {
    assert.ok(userIds.has(t.owner_id));
    assert.equal(t.owner_id, t.creator_id); // owner = creator
    assert.equal(t.assignee_id, null); // unassigned
    if (t.project_id) assert.ok(projIds.has(t.project_id), 'task project_id resolves');
    if (t.parent_id) assert.ok(taskIds.has(t.parent_id), 'task parent_id resolves');
  }
  for (const tl of rows(target, 'SELECT * FROM task_labels')) {
    assert.ok(taskIds.has(tl.task_id) && labelIds.has(tl.label_id), 'task_label refs resolve');
  }

  // ---- the subtask actually points at its parent's new id ----
  const t1 = rows(target, 'SELECT * FROM tasks').find((t) => t.title === 'root task');
  const t2 = rows(target, 'SELECT * FROM tasks').find((t) => t.title === 'subtask');
  assert.equal(t2.parent_id, t1.id);

  // ---- the multi-label task kept both labels ----
  const t4 = rows(target, 'SELECT * FROM tasks').find((t) => t.title === 'multi-label task');
  assert.equal(count2(target, t4.id), 2);

  // ---- user prefs carried; state_version dropped ----
  const u = rows(target, 'SELECT * FROM users')[0];
  assert.equal(u.username, 'alice');
  assert.equal(u.theme, 'matrix');
  assert.equal(u.week_start, 0);
  assert.equal(u.is_admin, 1);
  assert.equal(u.fib_sizing, 1);
  assert.equal(u.sort_prefs, '{"order":["due"]}');
});

function count2(db: Database.Database, taskId: string): number {
  return (
    db.prepare('SELECT COUNT(*) AS c FROM task_labels WHERE task_id = ?').get(taskId) as {
      c: number;
    }
  ).c;
}

// migrate-from-legacy.ts — one-time data migration from the legacy snapshot DB
// (composite (user_id,id) PKs, prefixed `t_N` ids) into the D1 schema (global
// UUID ids + owner_id). Per-user prefixed ids are remapped to UUIDs; parent /
// project / task_label refs are rewired to the new ids; owner_id = creator_id =
// the migrated user; no grants (default private); archived rows are preserved.
//
// Exposed as a function so the CI test can drive it over in-memory DBs; the CLI
// wrapper runs it file→file. The legacy `seq`/`state_version` machinery is dropped.

import { randomUUID } from 'node:crypto';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import Database from 'better-sqlite3';
import { openDatabase } from '../src/db.js';

type Sqlite = Database.Database;

export interface MigrationStats {
  users: number;
  projects: number;
  tasks: number;
  labels: number;
  taskLabels: number;
  savedQueries: number;
}

// `target` must already have the D1 schema applied (foreign_keys ON).
export function migrateFromLegacy(legacy: Sqlite, target: Sqlite): MigrationStats {
  const now = new Date().toISOString();
  // legacy ids are unique only within a user; key maps by (user_id, oldId).
  const key = (userId: string, oldId: string) => `${userId}�${oldId}`;

  const userMap = new Map<string, string>();
  const projMap = new Map<string, string>();
  const taskMap = new Map<string, string>();
  const labelMap = new Map<string, string>();
  const svMap = new Map<string, string>();

  const stats: MigrationStats = {
    users: 0,
    projects: 0,
    tasks: 0,
    labels: 0,
    taskLabels: 0,
    savedQueries: 0,
  };

  const all = (sql: string): any[] => legacy.prepare(sql).all() as any[];

  target.transaction(() => {
    // ---- users ----
    const insUser = target.prepare(
      `INSERT INTO users (id, username, email, password_hash, theme, week_start, sort_prefs, fib_sizing, is_admin, created_at, updated_at)
       VALUES (@id, @username, @email, @password_hash, @theme, @week_start, @sort_prefs, @fib_sizing, @is_admin, @created_at, @updated_at)`,
    );
    for (const u of all('SELECT * FROM users')) {
      const id = randomUUID();
      userMap.set(u.id, id);
      insUser.run({
        id,
        username: u.username,
        email: u.email,
        password_hash: u.password_hash,
        theme: u.theme ?? null,
        week_start: u.week_start ?? 1,
        sort_prefs: u.sort_prefs ?? null,
        fib_sizing: u.fib_sizing ?? 0,
        is_admin: u.is_admin ?? 0,
        created_at: u.created_at || now,
        updated_at: u.updated_at || now,
      });
      stats.users++;
    }

    // pre-allocate new ids so intra-set refs (parent/project/label) can be rewired
    const projects = all('SELECT * FROM projects');
    const labels = all('SELECT * FROM labels');
    const tasks = all('SELECT * FROM tasks');
    const savedQueries = all('SELECT * FROM saved_queries');
    for (const p of projects) projMap.set(key(p.user_id, p.id), randomUUID());
    for (const l of labels) labelMap.set(key(l.user_id, l.id), randomUUID());
    for (const t of tasks) taskMap.set(key(t.user_id, t.id), randomUUID());
    for (const s of savedQueries) svMap.set(key(s.user_id, s.id), randomUUID());

    // ---- projects ----
    const insProj = target.prepare(
      `INSERT INTO projects (id, owner_id, parent_id, name, color, glyph, collapsed, position, archived, health, created_at, updated_at)
       VALUES (@id, @owner_id, @parent_id, @name, @color, @glyph, @collapsed, @position, @archived, @health, @created_at, @updated_at)`,
    );
    for (const p of projects) {
      insProj.run({
        id: projMap.get(key(p.user_id, p.id)),
        owner_id: userMap.get(p.user_id),
        parent_id: p.parent_id ? (projMap.get(key(p.user_id, p.parent_id)) ?? null) : null,
        name: p.name,
        color: p.color,
        glyph: p.glyph,
        collapsed: p.collapsed ?? 0,
        position: p.position ?? 0,
        archived: p.archived ?? 0,
        health: p.health ?? '[]',
        created_at: now,
        updated_at: now,
      });
      stats.projects++;
    }

    // ---- labels ----
    const insLabel = target.prepare(
      'INSERT INTO labels (id, owner_id, name, pinned) VALUES (@id, @owner_id, @name, @pinned)',
    );
    for (const l of labels) {
      insLabel.run({
        id: labelMap.get(key(l.user_id, l.id)),
        owner_id: userMap.get(l.user_id),
        name: l.name,
        pinned: l.pinned ?? 0,
      });
      stats.labels++;
    }

    // ---- tasks ----
    const insTask = target.prepare(
      `INSERT INTO tasks (id, owner_id, creator_id, assignee_id, project_id, parent_id, title, done, due, reminder, recurrence, notes, priority, size, position, archived, created_at, completed_at, updated_at)
       VALUES (@id, @owner_id, @creator_id, @assignee_id, @project_id, @parent_id, @title, @done, @due, @reminder, @recurrence, @notes, @priority, @size, @position, @archived, @created_at, @completed_at, @updated_at)`,
    );
    for (const t of tasks) {
      const owner = userMap.get(t.user_id);
      insTask.run({
        id: taskMap.get(key(t.user_id, t.id)),
        owner_id: owner,
        creator_id: owner,
        assignee_id: null,
        project_id: t.project_id ? (projMap.get(key(t.user_id, t.project_id)) ?? null) : null,
        parent_id: t.parent_id ? (taskMap.get(key(t.user_id, t.parent_id)) ?? null) : null,
        title: t.title,
        done: t.done ?? 0,
        due: t.due ?? null,
        reminder: t.reminder ?? null,
        recurrence: t.recurrence ?? null,
        notes: t.notes ?? '',
        priority: t.priority ?? 0,
        size: t.size ?? 0,
        position: t.position ?? 0,
        archived: t.archived ?? 0,
        created_at: t.created_at || now,
        completed_at: t.completed_at ?? null,
        updated_at: now,
      });
      stats.tasks++;
    }

    // ---- task_labels (drop any row whose task or label didn't migrate) ----
    const insTL = target.prepare(
      'INSERT OR IGNORE INTO task_labels (task_id, label_id) VALUES (?, ?)',
    );
    for (const tl of all('SELECT * FROM task_labels')) {
      const newTask = taskMap.get(key(tl.user_id, tl.task_id));
      const newLabel = labelMap.get(key(tl.user_id, tl.label_id));
      if (newTask && newLabel) {
        insTL.run(newTask, newLabel);
        stats.taskLabels++;
      }
    }

    // ---- saved_queries ----
    const insSV = target.prepare(
      `INSERT INTO saved_queries (id, owner_id, name, glyph, query, system, color, position, pinned)
       VALUES (@id, @owner_id, @name, @glyph, @query, @system, @color, @position, @pinned)`,
    );
    for (const s of savedQueries) {
      insSV.run({
        id: svMap.get(key(s.user_id, s.id)),
        owner_id: userMap.get(s.user_id),
        name: s.name,
        glyph: s.glyph,
        query: s.query,
        system: s.system ?? 0,
        color: s.color ?? null,
        position: s.position ?? 0,
        pinned: s.pinned ?? 0,
      });
      stats.savedQueries++;
    }

    // carry over the instance backup settings (the target already seeded id=1)
    const hasBackupCfg = legacy
      .prepare("SELECT 1 FROM sqlite_master WHERE type='table' AND name='backup_config'")
      .get();
    if (hasBackupCfg) {
      const cfg = legacy.prepare('SELECT * FROM backup_config WHERE id = 1').get() as any;
      if (cfg) {
        target
          .prepare(
            'UPDATE backup_config SET enabled = ?, dir = ?, time_of_day = ?, retention = ? WHERE id = 1',
          )
          .run(
            cfg.enabled ?? 0,
            cfg.dir ?? '/backups',
            cfg.time_of_day ?? '02:00',
            cfg.retention ?? 7,
          );
      }
    }
  })();

  return stats;
}

// ---- CLI: tsx scripts/migrate-from-legacy.ts <legacy.db> [target.db] --------
const invokedDirectly =
  process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (invokedDirectly) {
  const legacyPath = process.argv[2] || process.env.LEGACY_DB_PATH;
  const targetPath = process.argv[3] || process.env.DB_PATH || './data/tdx.migrated.db';
  if (!legacyPath) {
    console.error('usage: tsx scripts/migrate-from-legacy.ts <legacy.db> [target.db]');
    console.error('  (point it at a COPY of the legacy DB; prod is never written)');
    process.exit(1);
  }
  const legacy = new Database(legacyPath, { readonly: true });
  const { sqlite: target } = openDatabase(targetPath);
  const stats = migrateFromLegacy(legacy, target);
  console.log(`[migrate] legacy ${legacyPath} -> ${targetPath}`);
  console.log('[migrate]', stats);
  legacy.close();
  target.close();
}

// db.ts — open SQLite (better-sqlite3), run the numbered .sql migrations, and
// expose a typed Kysely instance. Ported from backend/src/db.js; the migration
// runner is the same apply-in-order + schema_migrations pattern.

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import Database from 'better-sqlite3';
import { Kysely, SqliteDialect } from 'kysely';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

export const DEFAULT_DB_PATH =
  process.env.DB_PATH || path.join(__dirname, '..', 'data', 'tdx.dev.db');
// overridable so the compiled image (dist/) can point at the copied .sql files
export const MIGRATIONS_DIR =
  process.env.MIGRATIONS_DIR || path.join(__dirname, '..', 'migrations');

// ---- Kysely schema types ---------------------------------------------------
// SQLite has no boolean type; 0/1 integers are typed as `number`. Nullable
// columns are `T | null`. These mirror migrations/001_init.sql exactly.

export interface UsersTable {
  id: string;
  username: string;
  email: string;
  password_hash: string;
  theme: string | null;
  week_start: number;
  sort_prefs: string | null;
  fib_sizing: number;
  is_admin: number;
  created_at: string;
  updated_at: string;
}

export interface SessionsTable {
  id: string;
  user_id: string;
  created_at: string;
  expires_at: string;
  last_seen: string | null;
}

export interface ProjectsTable {
  id: string;
  owner_id: string;
  parent_id: string | null;
  name: string;
  color: string;
  glyph: string;
  collapsed: number;
  position: number;
  archived: number;
  health: string;
  created_at: string;
  updated_at: string;
}

export interface TasksTable {
  id: string;
  owner_id: string;
  creator_id: string;
  assignee_id: string | null;
  project_id: string | null;
  parent_id: string | null;
  title: string;
  done: number;
  due: string | null;
  reminder: string | null;
  recurrence: string | null;
  notes: string;
  priority: number;
  size: number;
  position: number;
  archived: number;
  created_at: string;
  completed_at: string | null;
  updated_at: string;
}

export interface EventsTable {
  id: string;
  owner_id: string;
  creator_id: string;
  assignee_id: string | null;
  title: string;
  notes: string;
  location: string | null;
  all_day: number;
  start_at: string;
  end_at: string | null;
  recurrence: string | null;
  reminder: string | null;
  position: number;
  archived: number;
  created_at: string;
  updated_at: string;
}

export interface NotesTable {
  id: string;
  owner_id: string;
  path: string;
  title: string;
  mtime: string;
  frontmatter: string | null;
  tombstoned: number;
  created_at: string;
  updated_at: string;
}

export interface NoteLinksTable {
  id: string;
  owner_id: string;
  origin_note_id: string;
  target_type: string;
  target_id: string;
  rel: string;
  created_at: string;
}

export interface LinksTable {
  id: string;
  owner_id: string;
  t1_type: string;
  t1_id: string;
  t2_type: string;
  t2_id: string;
  rel: string;
  data: string | null;
  created_at: string;
}

export interface LabelsTable {
  id: string;
  owner_id: string;
  name: string;
  pinned: number;
}

export interface TaskLabelsTable {
  task_id: string;
  label_id: string;
}

export interface SavedQueriesTable {
  id: string;
  owner_id: string;
  name: string;
  glyph: string;
  query: string;
  system: number;
  color: string | null;
  position: number;
  pinned: number;
}

export interface GrantsTable {
  id: string;
  resource_type: string;
  resource_id: string;
  principal_type: string;
  principal_id: string;
  role: string;
  created_at: string;
}

export interface GroupsTable {
  id: string;
  name: string;
  owner_id: string;
  created_at: string;
}

export interface GroupMembersTable {
  group_id: string;
  user_id: string;
  role: string;
  created_at: string;
}

export interface ApiTokensTable {
  id: string;
  user_id: string;
  name: string;
  token_hash: string;
  scopes: string;
  created_at: string;
  last_used_at: string | null;
  revoked_at: string | null;
}

export interface BackupConfigTable {
  id: number;
  enabled: number;
  dir: string;
  time_of_day: string;
  retention: number;
  last_run_at: string | null;
  last_status: string | null;
  last_error: string | null;
  next_run_at: string | null;
}

export interface Database_ {
  users: UsersTable;
  sessions: SessionsTable;
  projects: ProjectsTable;
  tasks: TasksTable;
  events: EventsTable;
  notes: NotesTable;
  note_links: NoteLinksTable;
  links: LinksTable;
  labels: LabelsTable;
  task_labels: TaskLabelsTable;
  saved_queries: SavedQueriesTable;
  grants: GrantsTable;
  groups: GroupsTable;
  group_members: GroupMembersTable;
  api_tokens: ApiTokensTable;
  backup_config: BackupConfigTable;
}

export type Sqlite = Database.Database;
export type DB = Kysely<Database_>;

// ---- migration runner ------------------------------------------------------
// Applies every *.sql file in migrations/ not yet recorded, in name order, each
// in its own transaction. Idempotent: re-running applies nothing new.
export function applyMigrations(sqlite: Sqlite, migrationsDir = MIGRATIONS_DIR): string[] {
  sqlite.exec(`CREATE TABLE IF NOT EXISTS schema_migrations (
    version    TEXT PRIMARY KEY,
    applied_at TEXT NOT NULL
  );`);

  const applied = new Set(
    sqlite
      .prepare('SELECT version FROM schema_migrations')
      .all()
      .map((r) => (r as { version: string }).version),
  );

  const files = fs
    .readdirSync(migrationsDir)
    .filter((f) => f.endsWith('.sql'))
    .sort();

  const record = sqlite.prepare(
    'INSERT INTO schema_migrations (version, applied_at) VALUES (?, ?)',
  );
  const newlyApplied: string[] = [];

  for (const file of files) {
    if (applied.has(file)) continue;
    const sql = fs.readFileSync(path.join(migrationsDir, file), 'utf8');
    sqlite.transaction(() => {
      sqlite.exec(sql);
      record.run(file, new Date().toISOString());
    })();
    newlyApplied.push(file);
  }
  return newlyApplied;
}

// Open a database file (or ':memory:'), set pragmas, migrate, and wrap in Kysely.
export function openDatabase(dbPath = DEFAULT_DB_PATH): { sqlite: Sqlite; db: DB } {
  if (dbPath !== ':memory:') fs.mkdirSync(path.dirname(dbPath), { recursive: true });
  const sqlite = new Database(dbPath);
  sqlite.pragma('journal_mode = WAL');
  sqlite.pragma('foreign_keys = ON');
  sqlite.pragma('synchronous = NORMAL');
  applyMigrations(sqlite);
  const db = new Kysely<Database_>({ dialect: new SqliteDialect({ database: sqlite }) });
  return { sqlite, db };
}

// `tsx src/db.ts --migrate` — apply migrations to DEFAULT_DB_PATH and report.
const invokedDirectly =
  process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (invokedDirectly) {
  fs.mkdirSync(path.dirname(DEFAULT_DB_PATH), { recursive: true });
  const sqlite = new Database(DEFAULT_DB_PATH);
  sqlite.pragma('journal_mode = WAL');
  sqlite.pragma('foreign_keys = ON');
  const applied = applyMigrations(sqlite);
  console.log(
    applied.length ? `[db] applied: ${applied.join(', ')}` : '[db] up to date (nothing to apply)',
  );
  console.log(`[db] ${DEFAULT_DB_PATH}`);
  sqlite.close();
}
